html:
{% set invoice_type_map = {
    "01": "Invoice",
    "02": "Credit Note",
    "03": "Debit Note",
    "04": "Refund Note",
    "11": "Self-billed Invoice",
    "12": "Self-billed Credit Note",
    "13": "Self-billed Debit Note",
    "14": "Self-billed Refund Note"
} %}
{% set inv_type_code = doc.e_invoice_type_code or doc.e_invoice_type or "01" %}
{% set inv_type = invoice_type_map.get(inv_type_code|string, "Invoice") %}

<style>
/* SCOPED CSS - Optimized for B&W Printing and ERPNext interface */
.e-inv-print {
    --ink: #1a202c; /* Charcoal for better B&W contrast */
    --ink-muted: #4a5568;
    --accent: #8b6d31; /* Bronze - turns to a clear medium gray in B&W */
    --accent-lt: #f7fafc;
    --rule: #cbd5e0;
    --white: #ffffff;

    font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
    font-size: 11.5px;
    color: var(--ink);
    line-height: 1.5;
    width: 100%;
    background: var(--white);
}

@media print {
    @page { size: A4 portrait; margin: 12mm; }
    .e-inv-print { width: 100%; }
    body { -webkit-print-color-adjust: exact; print-color-adjust: exact; }
}

/* ── TOP BAND (B&W FIXED) ─────────────────── */
.e-inv-print .top-band {
    background: #1a202c !important; /* High contrast charcoal */
    display: flex;
    justify-content: space-between;
    align-items: stretch;
    width: 100%;
    color: white !important;
}

.e-inv-print .top-band-left { padding: 22px 26px; flex: 1; }
.e-inv-print .doc-label { font-size: 9px; letter-spacing: 0.2em; text-transform: uppercase; color: #d4af37; font-weight: 700; margin-bottom: 5px; }
.e-inv-print h2 { font-size: 24px; font-weight: 700; color: white !important; margin: 0 0 7px 0 !important; }
.e-inv-print .company-addr { font-size: 10px; color: #e2e8f0; line-height: 1.6; }

.e-inv-print .top-band-right {
    background: #a88a4d !important; /* Medium bronze background */
    padding: 18px 22px;
    display: flex;
    align-items: center;
    gap: 20px;
    color: #1a202c !important;
}

.e-inv-print .inv-no { font-size: 18px; font-weight: 700; color: #1a202c !important; line-height: 1; }
.e-inv-print .inv-date { font-size: 11px; font-weight: 600; text-align: right; }

/* ── UUID STRIP ───────────────────────────── */
.e-inv-print .uuid-strip {
    background: #1a202c !important;
    padding: 8px 26px;
    border-top: 1px solid #4a5568;
}
.e-inv-print .uuid-label { color: #d4af37; font-size: 9px; font-weight: bold; margin-right: 10px; }
.e-inv-print .uuid-val { color: #cbd5e0; font-size: 9px; }

/* ── CARDS ────────────────────────────────── */
.e-inv-print .inner { padding: 25px; }
.e-inv-print .parties { display: grid; grid-template-columns: 1fr 1fr; gap: 15px; margin-bottom: 20px; }
.e-inv-print .party-card { background: #fff; border: 1px solid #cbd5e0; padding: 15px; border-left: 4px solid #1a202c; border-radius: 4px; }

/* ── TABLE (ALIGNMENT FIXED) ──────────────── */
.e-inv-print table.inv-table { width: 100%; border-collapse: collapse; margin-top: 10px; border: 1px solid #e2e8f0; }
.e-inv-print table.inv-table thead th { 
    background: #2d3748 !important; /* Dark gray */
    color: #ffffff !important; 
    padding: 10px; 
    text-align: left; 
    font-size: 10px;
    text-transform: uppercase;
}
.e-inv-print table.inv-table tbody td { 
    padding: 10px; 
    border-bottom: 1px solid #e2e8f0; 
    color: #000;
}

/* Force numeric columns to the right */
.e-inv-print .r { 
    text-align: right !important; 
    font-family: 'JetBrains Mono', monospace; 
    font-size: 10.5px;
}

/* ── TOTALS ───────────────────────────────── */
.e-inv-print .grand-row { background: #1a202c !important; color: white !important; }
.e-inv-print .gt-val { font-size: 22px; font-weight: bold; color: #ffffff !important; text-align: right !important; }
.e-inv-print .totals-table td { padding: 8px; border-bottom: 1px solid #e2e8f0; }
.e-inv-print .totals-table .grand-row td { border: none; }

/* ── QR CODE ──────────────────────────────── */
.e-inv-print .qr-wrap img {
    width: 75px; height: 75px;
    background: white;
    padding: 4px;
    border-radius: 4px;
    border: 1px solid #1a202c;
}
</style>

<div class="e-inv-print">
    <!-- HEADER -->
    <div class="top-band">
        <div class="top-band-left">
            <div class="doc-label">{{ inv_type }} v1.1 &nbsp;·&nbsp; E-Invoice</div>
            <h2>{{ doc.company }}</h2>
            <div class="company-addr">
                {{ doc.supplier_location or "" }}<br>
                {{ doc.supplier_city or "" }}{% if doc.supplier_state %}, {{ doc.supplier_state }}{% endif %}
            </div>
            <div style="margin-top:10px; font-size:9px; color:#cbd5e0">
                <strong>TIN</strong> {{ doc.supplier_tin or "—" }} &nbsp; 
                <strong>BRN</strong> {{ doc.supplier_brn or "—" }}
            </div>
        </div>

        <div class="top-band-right">
            <div style="text-align:right; margin-right:15px">
                <div class="inv-no">{{ doc.name }}</div>
                <div class="inv-date">{{ doc.get_formatted("posting_date") }}</div>
                <div style="font-size:8px; background:rgba(255,255,255,0.3); padding:2px 6px; border-radius:3px; margin-top:5px; font-weight:bold; display:inline-block">
                    {{ doc.custom_lhdn_e_invoice_status or "PENDING" }}
                </div>
            </div>
            {% if doc.validation_url %}
            <div class="qr-wrap">
                <img src="{{ doc.validation_url }}">
            </div>
            {% endif %}
        </div>
    </div>

    <!-- UUID -->
    <div class="uuid-strip">
        <span class="uuid-label">UUID</span>
        <span class="uuid-val">{{ doc.uuid or "N/A" }}</span>
    </div>

    <div class="inner">
        <!-- PARTIES -->
        <div class="parties">
            <div class="party-card">
                <div class="doc-label" style="color:#8b6d31">Supplier</div>
                <div style="font-weight:700; font-size:13px">{{ doc.company }}</div>
                <div style="font-size:10px; color:#4a5568">
                    TIN: {{ doc.supplier_tin or "—"}}<br>
                    BRN: {{ doc.supplier_brn or "—"}}<br>
                    MSIC:{{ doc.msic_codes or "—" }}
                </div>
            </div>
            <div class="party-card">
                <div class="doc-label" style="color:#8b6d31">Bill To</div>
                <div style="font-weight:700; font-size:13px">{{ doc.customer_name }}</div>
                <div style="font-size:10px; color:#4a5568">
                    {{ doc.address_line1 or "" }}<br>
                    TIN: {{ doc.customer_tin or "—" }}
                    BRN: {{ doc.customer_brn or "—" }}

                </div>
            </div>
        </div>

        <!-- ITEMS TABLE -->
        <table class="inv-table">
            <thead>
                <tr>
                    <th style="width:40px">#</th>
                    <th>Description</th>
                    <th class="r" style="width:80px">Qty</th>
                    <th class="r" style="width:100px">Rate</th>
                    <th class="r" style="width:110px">Amount</th>
                    <th class="r" style="width:110px">Classification Code</th>
                </tr>
            </thead>
            <tbody>
                {% for item in doc.items %}
                <tr>
                    <td>{{ item.idx }}</td>
                    <td><strong>{{ item.item_name }}</strong></td>
                    <!-- FIXED ALIGNMENT: Values are now under headers -->
                    <td class="r">{{ item.get_formatted("custom_item_classification_codes") }}</td>
                    <td class="r">{{ item.qty }}</td>
                    <td class="r">{{ item.get_formatted("rate") }}</td>
                    <td class="r">{{ item.get_formatted("amount") }}</td>

                </tr>
                {% endfor %}
            </tbody>
        </table>

        <!-- TOTALS SECTION -->
        <div style="display:flex; justify-content: space-between; margin-top:20px; align-items: flex-start;">
            <div style="background:#f7fafc; padding:15px; border-radius:4px; flex:1; margin-right:30px; border: 1px solid #e2e8f0;">
                <div class="doc-label" style="color:#8b6d31">Amount in Words</div>
                <div style="font-size:11px; font-weight: 600;">{{ doc.in_words }}</div>
            </div>
            <div style="width:300px">
                <table class="totals-table" style="width:100%; border-collapse:collapse">
                    <tr>
                        <td>Net Total</td>
                        <td class="r" style="font-weight:700">{{ doc.get_formatted("net_total") }}</td>
                    </tr>
                    <tr>
                        <td>Tax Total</td>
                        <td class="r" style="font-weight:700">{{ doc.get_formatted("total_taxes_and_charges") }}</td>
                    </tr>
                    <tr class="grand-row">
                        <td style="padding:15px; font-weight:700; color:white;">GRAND TOTAL</td>
                        <td class="r gt-val" style="padding:15px; color:white !important;">{{ doc.get_formatted("grand_total") }}</td>
                    </tr>
                </table>
            </div>
        </div>
    </div>
</div>
